+                &mut self,
+                _cx: &Cx,
+                frames: &[crate::traits::WalFrameRef<'_>],
+            ) -> fsqlite_error::Result<()> {
+                *self.append_calls.lock().unwrap() += 1;
+                std::thread::sleep(self.io_delay);
+                let _ = frames;
+                Ok(())
